export async function main(_ctx, _input) {
  const emoji = '\u{1F600}';
  const decomposed = 'e\u0301';
  return { ok: true, value: {
    units: emoji.length,
    points: [...emoji].length,
    codePoint: emoji.codePointAt(0),
    nfc: decomposed.normalize('NFC'),
    nfcLen: decomposed.normalize('NFC').length,
    upper: '\u00df'.toUpperCase(),
    loneSurrogate: '\uD800'.length
  } };
}
